import React, { useEffect, useState } from "react";
import API from "../../api/api";

const formatDate = (d) => d
  ? new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" })
  : "";

const statusStyle = (s) => {
  if (s === "accepted") return "bg-green-100 text-green-700";
  if (s === "rejected") return "bg-red-100 text-red-600";
  return "bg-yellow-100 text-yellow-700";
};

const Earnings = () => {
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading]     = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const res = await API.get("/proposals/my");
        setProposals(res.data || []);
      } catch {}
      setLoading(false);
    };
    load();
  }, []);

  const accepted  = proposals.filter(p => p.status === "accepted");
  const pending   = proposals.filter(p => !p.status || p.status === "pending");
  const rejected  = proposals.filter(p => p.status === "rejected");

  // ✅ FIX: Total Earned = ₹0 always (no payment system yet)
  // Accepted bid value shown separately as "Accepted Value" — not "earned"
  const acceptedValue = accepted.reduce((s, p) => s + parseFloat(p.bid || 0), 0);
  const pendingValue  = pending.reduce((s, p) => s + parseFloat(p.bid || 0), 0);

  if (loading) return <div className="text-center py-10 text-gray-400">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-5xl mx-auto">

        <h1 className="text-2xl font-bold text-gray-800 mb-1">Earnings Dashboard</h1>
        <p className="text-gray-500 mb-6 text-sm">Track your bids and proposal income</p>

        {/* ✅ STAT CARDS — Total Earned shows ₹0 */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
          <div className="bg-white rounded-xl p-5 shadow-sm border-l-4 border-green-500">
            <p className="text-xs text-gray-500 mb-1">Total Earned</p>
            <p className="text-2xl font-bold text-green-600">₹0</p>
            <p className="text-xs text-gray-400 mt-1">No withdrawals yet</p>
          </div>
          <div className="bg-white rounded-xl p-5 shadow-sm border-l-4 border-blue-500">
            <p className="text-xs text-gray-500 mb-1">Accepted Value</p>
            <p className="text-2xl font-bold text-blue-600">
              {acceptedValue > 0 ? `₹${acceptedValue.toLocaleString()}` : "₹0"}
            </p>
            <p className="text-xs text-gray-400 mt-1">From accepted bids</p>
          </div>
          <div className="bg-white rounded-xl p-5 shadow-sm border-l-4 border-yellow-500">
            <p className="text-xs text-gray-500 mb-1">Pending Value</p>
            <p className="text-2xl font-bold text-yellow-600">
              {pendingValue > 0 ? `₹${pendingValue.toLocaleString()}` : "₹0"}
            </p>
            <p className="text-xs text-gray-400 mt-1">Awaiting decision</p>
          </div>
          <div className="bg-white rounded-xl p-5 shadow-sm border-l-4 border-teal-500">
            <p className="text-xs text-gray-500 mb-1">Total Proposals</p>
            <p className="text-2xl font-bold text-teal-600">{proposals.length}</p>
            <p className="text-xs text-gray-400 mt-1">All time</p>
          </div>
        </div>

        {/* STATUS BREAKDOWN */}
        <div className="grid grid-cols-3 gap-4 mb-8">
          <div className="bg-green-50 border border-green-100 rounded-xl p-4 text-center">
            <p className="text-3xl font-bold text-green-700">{accepted.length}</p>
            <p className="text-sm mt-1 text-green-600 font-medium">✅ Accepted</p>
          </div>
          <div className="bg-yellow-50 border border-yellow-100 rounded-xl p-4 text-center">
            <p className="text-3xl font-bold text-yellow-700">{pending.length}</p>
            <p className="text-sm mt-1 text-yellow-600 font-medium">⏳ Pending</p>
          </div>
          <div className="bg-red-50 border border-red-100 rounded-xl p-4 text-center">
            <p className="text-3xl font-bold text-red-600">{rejected.length}</p>
            <p className="text-sm mt-1 text-red-500 font-medium">❌ Rejected</p>
          </div>
        </div>

        {/* PROPOSALS TABLE */}
        <div className="bg-white rounded-xl shadow overflow-hidden border border-gray-100">
          <div className="px-5 py-4 border-b border-gray-100">
            <h2 className="font-bold text-gray-700">All Proposals & Earnings</h2>
          </div>
          {proposals.length === 0 ? (
            <div className="text-center py-12 text-gray-400">
              <div className="text-4xl mb-2">💸</div>
              <p>No proposals yet. Start bidding on projects!</p>
            </div>
          ) : (
            <table className="w-full text-sm">
              <thead className="bg-gray-50 border-b border-gray-100">
                <tr>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Project</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Your Bid</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Project Budget</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Date</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {proposals.map(p => (
                  <tr key={p.id} className="hover:bg-gray-50 transition">
                    <td className="px-5 py-4 font-medium text-gray-800">{p.project_title}</td>
                    <td className="px-5 py-4 font-bold text-teal-600">₹{p.bid}</td>
                    <td className="px-5 py-4 text-gray-500">₹{p.project_budget || "—"}</td>
                    <td className="px-5 py-4 text-gray-400">{formatDate(p.created_at)}</td>
                    <td className="px-5 py-4">
                      <span className={`px-2 py-1 rounded-full text-xs font-semibold capitalize ${statusStyle(p.status)}`}>
                        {p.status || "pending"}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>

      </div>
    </div>
  );
};

export default Earnings;
